[
  {
    "finding_id": "F1",
    "title": "Systematic Circumvention of Overtime Reporting",
    "details": "The Cardiac ICU scheduling system (CareScheduler) has been systematically populated with scheduled hours rather than actual hours worked for at least 4 months (November 2025 through March 2026). Lead Charge Nurse Donna Park stated she was instructed by outgoing Nurse Manager Linda Yee to 'enter the scheduled hours' because 'the administration needs clean numbers and we can manage the overtime informally.'",
    "regulatory_citation": "",
    "severity": "critical"
  },
  {
    "finding_id": "F2",
    "title": "Scope of Under-Reporting",
    "details": "The systematic under-reporting affected 9 of 11 full-time cardiac ICU nurses, with an average actual badge-data average of 58.2 h/week compared to a reported 40.7 h/week. The two charge nurses, Donna Park (RN-01) and David Okafor (RN-06), had accurate records, indicating the pattern is inconsistent with random error.",
    "regulatory_citation": "",
    "severity": "high"
  },
  {
    "finding_id": "F3",
    "title": "Patient Safety Implications",
    "details": "Three nurses averaged 68-72 hours per week, creating an estimated 3-fold increase in medication error probability and cognitive performance equivalent to 0.08% BAC. Two informal near-miss events (medication dosage confusion on W1 Day 4 and wrong-route administration on W-2) were documented in independent sources but not reported through ClinAlert.",
    "regulatory_citation": "",
    "severity": "critical"
  },
  {
    "finding_id": "F4",
    "title": "Mandatory Reporting Obligation",
    "details": "This finding is subject to mandatory self-report to the Washington State Department of Health within 72 hours of the formal finding date due to the documented patient safety events and systematic under-reporting.",
    "regulatory_citation": "RCW 70.41.230",
    "severity": "critical"
  }
]
